{
  "name": "بيت العسل - Honey House",
  "description": "A professional landing page and order system for Honey House, featuring premium Egyptian honey products with direct WhatsApp ordering."
}

export type Language = 'ar' | 'en';

export interface ProductPrice {
  sizeAr: string;
  sizeEn: string;
  price: number;
  id: string;
}

export interface Product {
  id: string;
  titleAr: string;
  titleEn: string;
  descriptionAr: string;
  descriptionEn: string;
  image: string;
  prices: ProductPrice[];
  featuresAr?: string[];
  featuresEn?: string[];
}

export interface CartItem {
  id: string; // Unique UI ID for the row
  productId: string;
  priceId: string;
  quantity: number;
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { Language, CartItem, Product, ProductPrice } from './types';
import { PRODUCTS, TRANSLATIONS, WHATSAPP_NUMBER } from './constants';

const App: React.FC = () => {
  const [lang, setLang] = useState<Language>('ar');
  const [cart, setCart] = useState<CartItem[]>([{ id: 'init-1', productId: PRODUCTS[0].id, priceId: PRODUCTS[0].prices[0].id, quantity: 1 }]);
  const [customer, setCustomer] = useState({ name: '', phone: '', location: '' });

  const t = useMemo(() => TRANSLATIONS[lang], [lang]);

  useEffect(() => {
    document.documentElement.dir = lang === 'ar' ? 'rtl' : 'ltr';
    document.documentElement.lang = lang;
  }, [lang]);

  const toggleLanguage = () => setLang(prev => (prev === 'ar' ? 'en' : 'ar'));

  const addProductLine = () => {
    const newItem: CartItem = {
      id: Math.random().toString(36).substr(2, 9),
      productId: PRODUCTS[0].id,
      priceId: PRODUCTS[0].prices[0].id,
      quantity: 1
    };
    setCart([...cart, newItem]);
  };

  const removeProductLine = (id: string) => {
    setCart(cart.filter(item => item.id !== id));
  };

  const updateCartItem = (id: string, field: keyof CartItem, value: any) => {
    setCart(cart.map(item => {
      if (item.id === id) {
        const updated = { ...item, [field]: value };
        // Reset price if product changed
        if (field === 'productId') {
          const product = PRODUCTS.find(p => p.id === value);
          updated.priceId = product ? product.prices[0].id : '';
        }
        return updated;
      }
      return item;
    }));
  };

  const totalOrderPrice = useMemo(() => {
    return cart.reduce((acc, item) => {
      const product = PRODUCTS.find(p => p.id === item.productId);
      const priceObj = product?.prices.find(pr => pr.id === item.priceId);
      return acc + (priceObj ? priceObj.price * item.quantity : 0);
    }, 0);
  }, [cart]);

  const handleSendOrder = () => {
    if (!customer.name || !customer.phone || !customer.location || cart.length === 0) {
      alert(t.errorFields);
      return;
    }

    let summary = '';
    cart.forEach((item, index) => {
      const product = PRODUCTS.find(p => p.id === item.productId);
      const priceObj = product?.prices.find(pr => pr.id === item.priceId);
      if (product && priceObj) {
        const prodName = lang === 'ar' ? product.titleAr : product.titleEn;
        const sizeName = lang === 'ar' ? priceObj.sizeAr : priceObj.sizeEn;
        summary += `${index + 1}. ${prodName} (${sizeName}) x ${item.quantity}\n`;
      }
    });

    const msg = `${t.whatsappOrderHeader}\n\n` +
                `${t.whatsappName} ${customer.name}\n` +
                `${t.whatsappPhone} ${customer.phone}\n` +
                `${t.whatsappLocation} ${customer.location}\n\n` +
                `${summary}\n` +
                `${t.whatsappTotal} ${totalOrderPrice} ${t.currency}`;

    window.open(`https://wa.me/${WHATSAPP_NUMBER}?text=${encodeURIComponent(msg)}`, '_blank');
  };

  const handleInquiry = () => {
    const msg = lang === 'ar' ? 'مرحباً بيت العسل، لدي استفسار عام.' : 'Hello Honey House, I have a general inquiry.';
    window.open(`https://wa.me/${WHATSAPP_NUMBER}?text=${encodeURIComponent(msg)}`, '_blank');
  };

  return (
    <div className={`min-h-screen pb-20 px-4 pt-4 sm:px-6 lg:px-8 max-w-5xl mx-auto ${lang === 'en' ? 'font-inter' : 'font-cairo'}`}>

      {/* Header Section */}
      <header className="relative text-center mb-12 flex flex-col items-center">
        <button 
          onClick={toggleLanguage}
          className="absolute top-0 right-0 md:right-4 bg-amber-200 text-amber-800 py-1.5 px-4 rounded-full text-sm font-bold shadow-sm transition hover:bg-amber-300 z-10"
        >
          {lang === 'ar' ? 'English' : 'العربية'}
        </button>

        <div className="relative w-40 h-40 md:w-48 md:h-48 mb-6 group">
          <div className="absolute inset-0 honey-gradient rounded-full shadow-lg group-hover:scale-105 transition-transform duration-500"></div>
          <img 
            src="https://imgur.com/doKxqHM.jpeg" 
            alt="Logo" 
            className="absolute inset-0 w-full h-full object-contain p-4 rounded-full"
          />
        </div>

        <h1 className="text-4xl md:text-5xl font-extrabold text-[#6B4226] mb-3">{t.companyName}</h1>
        <p className="text-lg md:text-xl text-[#A16207] italic max-w-2xl mb-6">{t.slogan}</p>

        <div className="inline-block px-6 py-2.5 bg-amber-50 rounded-full border-2 border-amber-300 shadow-sm animate-pulse">
          <span className="text-xl font-bold text-amber-700">{t.deliveryNote}</span>
        </div>
      </header>

      {/* Offers Banner */}
      <div className="bg-amber-100 border-r-4 border-l-4 border-amber-500 p-6 rounded-2xl shadow-md text-center mb-16 max-w-3xl mx-auto">
        <h2 className="text-2xl md:text-3xl font-black text-amber-900 mb-2">{t.grandOpening}</h2>
        <p className="text-xl font-bold text-amber-800">{t.limitedTime}</p>
      </div>

      {/* Products Grid */}
      <main className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8 mb-20">
        {PRODUCTS.map((product) => (
          <ProductCard 
            key={product.id} 
            product={product} 
            lang={lang} 
            currency={t.currency}
            chooseSizeText={t.chooseSize}
          />
        ))}
      </main>

      {/* Order Form Section */}
      <section id="order-section" className="bg-white p-8 rounded-3xl shadow-2xl border border-amber-50 max-w-4xl mx-auto scroll-mt-20">
        <div className="text-center mb-8">
          <h3 className="text-3xl font-bold text-[#6B4226] mb-2">{t.orderNow}</h3>
          <p className="text-lg text-[#A16207]">{t.fillForm}</p>
        </div>

        <div className="space-y-6">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="space-y-1">
              <label className="block text-lg font-semibold text-[#6B4226]">{t.nameLabel}</label>
              <input 
                type="text" 
                value={customer.name}
                onChange={(e) => setCustomer({...customer, name: e.target.value})}
                className="w-full p-3.5 border border-amber-200 rounded-xl focus:ring-4 focus:ring-amber-500/20 focus:border-amber-500 outline-none transition-all"
                placeholder={t.namePlaceholder}
              />
            </div>
            <div className="space-y-1">
              <label className="block text-lg font-semibold text-[#6B4226]">{t.phoneLabel}</label>
              <input 
                type="tel" 
                value={customer.phone}
                onChange={(e) => setCustomer({...customer, phone: e.target.value})}
                className="w-full p-3.5 border border-amber-200 rounded-xl focus:ring-4 focus:ring-amber-500/20 focus:border-amber-500 outline-none transition-all text-left"
                placeholder={t.phonePlaceholder}
              />
            </div>
          </div>

          <div className="space-y-1">
            <label className="block text-lg font-semibold text-[#6B4226]">{t.locationLabel}</label>
            <input 
              type="text" 
              value={customer.location}
              onChange={(e) => setCustomer({...customer, location: e.target.value})}
              className="w-full p-3.5 border border-amber-200 rounded-xl focus:ring-4 focus:ring-amber-500/20 focus:border-amber-500 outline-none transition-all"
              placeholder={t.locationPlaceholder}
            />
          </div>

          <div className="bg-amber-50/50 p-6 rounded-2xl border border-amber-100 space-y-4">
            {cart.map((item) => (
              <div key={item.id} className="flex flex-col sm:flex-row gap-4 items-end pb-4 border-b border-amber-100 last:border-0 last:pb-0">
                <div className="flex-grow w-full">
                  <label className="block text-sm font-bold text-amber-800 mb-1">{t.productSelectLabel}</label>
                  <select 
                    value={item.productId}
                    onChange={(e) => updateCartItem(item.id, 'productId', e.target.value)}
                    className="w-full p-3 border border-amber-300 rounded-lg bg-white appearance-none cursor-pointer focus:ring-2 focus:ring-amber-500 outline-none"
                  >
                    {PRODUCTS.map(p => (
                      <option key={p.id} value={p.id}>{lang === 'ar' ? p.titleAr : p.titleEn}</option>
                    ))}
                  </select>
                </div>

                <div className="w-full sm:w-32">
                  <label className="block text-sm font-bold text-amber-800 mb-1">{t.chooseSize}</label>
                  <select 
                    value={item.priceId}
                    onChange={(e) => updateCartItem(item.id, 'priceId', e.target.value)}
                    className="w-full p-3 border border-amber-300 rounded-lg bg-white appearance-none cursor-pointer focus:ring-2 focus:ring-amber-500 outline-none"
                  >
                    {PRODUCTS.find(p => p.id === item.productId)?.prices.map(pr => (
                      <option key={pr.id} value={pr.id}>{lang === 'ar' ? pr.sizeAr : pr.sizeEn} ({pr.price} {t.currency})</option>
                    ))}
                  </select>
                </div>

                <div className="w-full sm:w-24">
                  <label className="block text-sm font-bold text-amber-800 mb-1">{t.quantityLabel}</label>
                  <input 
                    type="number" 
                    min="1" 
                    value={item.quantity}
                    onChange={(e) => updateCartItem(item.id, 'quantity', parseInt(e.target.value) || 1)}
                    className="w-full p-3 border border-amber-300 rounded-lg focus:ring-2 focus:ring-amber-500 outline-none"
                  />
                </div>

                {cart.length > 1 && (
                  <button 
                    onClick={() => removeProductLine(item.id)}
                    className="bg-red-50 text-red-600 font-bold py-3 px-4 rounded-lg hover:bg-red-100 transition-colors"
                  >
                    {t.remove}
                  </button>
                )}
              </div>
            ))}

            <button 
              onClick={addProductLine}
              className="w-full bg-amber-200 text-amber-900 font-bold py-3 rounded-xl hover:bg-amber-300 transition-colors flex items-center justify-center gap-2"
            >
              <span className="text-xl">+</span> {t.addProduct}
            </button>
          </div>

          <div className="flex flex-col items-center py-6">
            <p className="text-4xl font-black text-amber-600 mb-8">
              {t.total} {totalOrderPrice} {t.currency}
            </p>

            <div className="flex flex-col sm:flex-row gap-4 w-full justify-center">
              <button 
                onClick={handleSendOrder}
                className="w-full sm:w-auto bg-amber-500 hover:bg-amber-600 text-white font-black py-4 px-10 rounded-2xl shadow-xl transform hover:-translate-y-1 transition-all text-xl"
              >
                {t.sendOrder}
              </button>
              <button 
                onClick={handleInquiry}
                className="w-full sm:w-auto bg-slate-100 hover:bg-slate-200 text-slate-700 font-bold py-4 px-10 rounded-2xl transition-all"
              >
                {t.inquiry}
              </button>
            </div>
          </div>
        </div>
      </section>

      {/* Sticky Bottom Order Summary for Mobile */}
      <div className="fixed bottom-0 left-0 right-0 p-4 md:hidden z-20 pointer-events-none">
        <div className="bg-amber-500 text-white p-3 rounded-2xl shadow-2xl flex justify-between items-center pointer-events-auto">
          <div className="text-lg font-bold">
            {t.total} {totalOrderPrice} {t.currency}
          </div>
          <button 
            onClick={() => document.getElementById('order-section')?.scrollIntoView({ behavior: 'smooth' })}
            className="bg-white text-amber-600 px-5 py-2 rounded-xl font-bold shadow-sm"
          >
            {t.sendOrder}
          </button>
        </div>
      </div>
    </div>
  );
};

// --- Child Components ---

interface ProductCardProps {
  product: Product;
  lang: Language;
  currency: string;
  chooseSizeText: string;
}

const ProductCard: React.FC<ProductCardProps> = ({ product, lang, currency, chooseSizeText }) => {
  const [selectedPriceIndex, setSelectedPriceIndex] = useState(0);
  const currentPrice = product.prices[selectedPriceIndex];

  return (
    <div className="bg-white rounded-3xl shadow-xl overflow-hidden flex flex-col group hover:shadow-2xl transition-all duration-300 transform hover:-translate-y-1 border border-amber-50">
      <div className="relative h-64 sm:h-72 overflow-hidden bg-amber-50/30 flex items-center justify-center p-4">
        <img 
          src={product.image} 
          alt={lang === 'ar' ? product.titleAr : product.titleEn} 
          className="max-h-full max-w-full object-contain group-hover:scale-110 transition-transform duration-700"
        />
        <div className="absolute top-4 left-4 right-4 flex justify-between">
            {product.prices.length > 1 && (
                <div className="bg-amber-500 text-white text-xs font-bold px-2.5 py-1 rounded-full uppercase">
                    {lang === 'ar' ? 'أحجام متعددة' : 'Multi-Size'}
                </div>
            )}
        </div>
      </div>

      <div className="p-6 flex-grow flex flex-col">
        <h3 className="text-2xl font-bold text-[#6B4226] mb-3 h-16 overflow-hidden">
          {lang === 'ar' ? product.titleAr : product.titleEn}
        </h3>

        <p className="text-amber-700/80 mb-6 text-sm flex-grow line-clamp-4">
          {lang === 'ar' ? product.descriptionAr : product.descriptionEn}
        </p>

        {(product.featuresAr || product.featuresEn) && (
          <ul className="mb-6 space-y-2">
            {(lang === 'ar' ? product.featuresAr : product.featuresEn)?.map((feat, i) => (
              <li key={i} className="flex items-center gap-2 text-sm text-amber-900 font-semibold">
                <span className="w-2 h-2 bg-amber-400 rounded-full"></span>
                {feat}
              </li>
            ))}
          </ul>
        )}

        {product.prices.length > 1 && (
          <div className="mb-6">
            <p className="text-xs font-bold text-amber-600 mb-2 uppercase tracking-wider">{chooseSizeText}</p>
            <div className="flex flex-wrap gap-2">
              {product.prices.map((p, idx) => (
                <button
                  key={p.id}
                  onClick={() => setSelectedPriceIndex(idx)}
                  className={`px-4 py-1.5 rounded-full text-xs font-bold border-2 transition-all ${
                    selectedPriceIndex === idx 
                      ? 'bg-amber-500 border-amber-500 text-white shadow-md' 
                      : 'border-amber-200 text-amber-700 hover:border-amber-400'
                  }`}
                >
                  {lang === 'ar' ? p.sizeAr : p.sizeEn}
                </button>
              ))}
            </div>
          </div>
        )}

        <div className="mt-auto flex items-center justify-between border-t border-amber-50 pt-4">
          <div className="text-3xl font-black text-amber-600">
            {currentPrice.price} <span className="text-sm font-bold opacity-80">{currency}</span>
          </div>
          <button 
            onClick={() => {
                document.getElementById('order-section')?.scrollIntoView({ behavior: 'smooth' });
            }}
            className="bg-amber-100 hover:bg-amber-200 text-amber-800 p-2.5 rounded-xl transition-colors"
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 3h2l.4 2M7 13h10l4-8H5.4M7 13L5.4 5M7 13l-2.293 2.293c-.63.63-.184 1.707.707 1.707H17m0 0a2 2 0 100 4 2 2 0 000-4zm-8 2a2 2 0 11-4 0 2 2 0 014 0z" />
            </svg>
          </button>
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Language, CartItem, Product } from './types';
import { PRODUCTS, TRANSLATIONS, WHATSAPP_NUMBER, FAQS } from './constants';
import { GoogleGenAI } from "@google/genai";

const App: React.FC = () => {
  const [lang, setLang] = useState<Language>('ar');
  const [cart, setCart] = useState<CartItem[]>([{ id: 'init-1', productId: PRODUCTS[0].id, priceId: PRODUCTS[0].prices[0].id, quantity: 1 }]);
  const [customer, setCustomer] = useState({ name: '', phone: '', location: '' });
  const [isAiOpen, setIsAiOpen] = useState(false);
  const [aiMessage, setAiMessage] = useState('');
  const [aiResponse, setAiResponse] = useState('');
  const [isAiThinking, setIsAiThinking] = useState(false);

  const t = useMemo(() => TRANSLATIONS[lang], [lang]);

  useEffect(() => {
    document.documentElement.dir = lang === 'ar' ? 'rtl' : 'ltr';
    document.documentElement.lang = lang;
  }, [lang]);

  const toggleLanguage = () => setLang(prev => (prev === 'ar' ? 'en' : 'ar'));

  const addProductLine = () => {
    const newItem: CartItem = {
      id: Math.random().toString(36).substr(2, 9),
      productId: PRODUCTS[0].id,
      priceId: PRODUCTS[0].prices[0].id,
      quantity: 1
    };
    setCart([...cart, newItem]);
  };

  const removeProductLine = (id: string) => {
    setCart(cart.filter(item => item.id !== id));
  };

  const updateCartItem = (id: string, field: keyof CartItem, value: any) => {
    setCart(cart.map(item => {
      if (item.id === id) {
        const updated = { ...item, [field]: value };
        if (field === 'productId') {
          const product = PRODUCTS.find(p => p.id === value);
          updated.priceId = product ? product.prices[0].id : '';
        }
        return updated;
      }
      return item;
    }));
  };

  const totalOrderPrice = useMemo(() => {
    return cart.reduce((acc, item) => {
      const product = PRODUCTS.find(p => p.id === item.productId);
      const priceObj = product?.prices.find(pr => pr.id === item.priceId);
      return acc + (priceObj ? priceObj.price * item.quantity : 0);
    }, 0);
  }, [cart]);

  const handleSendOrder = () => {
    if (!customer.name || !customer.phone || !customer.location || cart.length === 0) {
      alert(t.errorFields);
      return;
    }

    let summary = '';
    cart.forEach((item, index) => {
      const product = PRODUCTS.find(p => p.id === item.productId);
      const priceObj = product?.prices.find(pr => pr.id === item.priceId);
      if (product && priceObj) {
        const prodName = lang === 'ar' ? product.titleAr : product.titleEn;
        const sizeName = lang === 'ar' ? priceObj.sizeAr : priceObj.sizeEn;
        summary += `${index + 1}. ${prodName} (${sizeName}) x ${item.quantity}\n`;
      }
    });

    const msg = `${t.whatsappOrderHeader}\n\n` +
                `${t.whatsappName} ${customer.name}\n` +
                `${t.whatsappPhone} ${customer.phone}\n` +
                `${t.whatsappLocation} ${customer.location}\n\n` +
                `${summary}\n` +
                `${t.whatsappTotal} ${totalOrderPrice} ${t.currency}`;

    window.open(`https://wa.me/${WHATSAPP_NUMBER}?text=${encodeURIComponent(msg)}`, '_blank');
  };

  const handleAiConsult = async () => {
    if (!aiMessage.trim()) return;
    setIsAiThinking(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `
        You are a professional honey sommelier for "Honey House". 
        Language: ${lang === 'ar' ? 'Arabic' : 'English'}.
        Product Catalog: ${JSON.stringify(PRODUCTS.map(p => ({
          name: lang === 'ar' ? p.titleAr : p.titleEn,
          desc: lang === 'ar' ? p.descriptionAr : p.descriptionEn,
          features: lang === 'ar' ? p.featuresAr : p.featuresEn
        })))}
        User Query: ${aiMessage}
        Task: Provide a helpful, warm, and professional response. Recommend a specific product from our list if it fits their needs. Keep it concise.
      `;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt
      });
      setAiResponse(response.text || '');
    } catch (error) {
      console.error(error);
      setAiResponse(lang === 'ar' ? 'عذراً، حدث خطأ. حاول مجدداً.' : 'Sorry, an error occurred. Please try again.');
    } finally {
      setIsAiThinking(false);
    }
  };

  return (
    <div className={`min-h-screen pb-24 text-slate-900 bg-[#FEFBF6]`}>

      {/* Navbar / Language Switcher */}
      <nav className="sticky top-0 z-30 bg-white/80 backdrop-blur-md border-b border-amber-100 px-4 py-3 flex justify-between items-center max-w-7xl mx-auto rounded-b-2xl shadow-sm">
        <div className="flex items-center gap-2">
           <img src="https://imgur.com/doKxqHM.jpeg" alt="Logo" className="w-10 h-10 rounded-full" />
           <span className="text-xl font-bold text-amber-900">{t.companyName}</span>
        </div>
        <button 
          onClick={toggleLanguage}
          className="bg-amber-100 text-amber-800 py-1.5 px-5 rounded-full text-sm font-bold hover:bg-amber-200 transition-colors"
        >
          {lang === 'ar' ? 'English' : 'العربية'}
        </button>
      </nav>

      <div className={`max-w-6xl mx-auto px-4 mt-8 ${lang === 'en' ? 'font-inter' : 'font-cairo'}`}>

        {/* Hero Section */}
        <section className="text-center mb-16 relative py-12">
          <div className="absolute top-0 left-1/2 -translate-x-1/2 w-64 h-64 bg-amber-200/20 blur-3xl rounded-full -z-10"></div>
          <h1 className="text-5xl md:text-7xl font-black text-amber-900 mb-4 tracking-tight">
            {t.companyName}
          </h1>
          <p className="text-xl md:text-2xl text-amber-700/90 font-medium mb-8 max-w-2xl mx-auto leading-relaxed">
            {t.slogan}
          </p>
          <div className="flex flex-wrap justify-center gap-4">
            <span className="bg-amber-500 text-white px-6 py-2 rounded-full font-bold shadow-lg shadow-amber-500/30">
              {t.deliveryNote}
            </span>
          </div>
        </section>

        {/* Why Us Section */}
        <section className="mb-20">
          <h2 className="text-3xl font-bold text-center text-amber-900 mb-10">{t.whyChooseUs}</h2>
          <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
            <WhyUsItem icon="🌿" title={t.natural} />
            <WhyUsItem icon="🔬" title={t.labTested} />
            <WhyUsItem icon="🐝" title={t.direct} />
            <WhyUsItem icon="⚡" title={t.fastDelivery} />
          </div>
        </section>

        {/* Products Grid */}
        <section className="mb-20">
          <div className="bg-amber-100/50 p-6 rounded-3xl mb-12 text-center border-2 border-dashed border-amber-300">
             <h3 className="text-2xl font-black text-amber-800">{t.grandOpening}</h3>
             <p className="text-amber-700 font-bold">{t.limitedTime}</p>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-10">
            {PRODUCTS.map((product) => (
              <ProductCard 
