        className="flex-grow p-3 bg-slate-50 rounded-xl outline-none text-amber-900 font-bold w-full"
      >
        {PRODUCTS.map(p => <option key={p.id} value={p.id}>{lang === 'ar' ? p.titleAr : p.titleEn}</option>)}
      </select>
      <select 
        value={item.priceId} 
        onChange={e => onUpdate(item.id, 'priceId', e.target.value)}
        className="w-full sm:w-40 p-3 bg-slate-50 rounded-xl outline-none text-amber-700"
      >
        {prod?.prices.map(pr => <option key={pr.id} value={pr.id}>{lang === 'ar' ? pr.sizeAr : pr.sizeEn} ({pr.price} {t.currency})</option>)}
      </select>
      <div className="flex items-center gap-3 w-full sm:w-auto">
        <input 
          type="number" 
          min="1" 
          value={item.quantity} 
          onChange={e => onUpdate(item.id, 'quantity', parseInt(e.target.value) || 1)}
          className="w-full sm:w-20 p-3 bg-slate-50 rounded-xl text-center font-bold outline-none"
        />
        {!isOnly && <button onClick={onRemove} className="bg-red-50 text-red-500 p-3 rounded-xl hover:bg-red-100 transition-colors">✕</button>}
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { Language, CartItem } from './types';
import { PRODUCTS, TRANSLATIONS, WHATSAPP_NUMBER, FAQS } from './constants';
import { GoogleGenAI } from "@google/genai";

const App: React.FC = () => {
  const [lang, setLang] = useState<Language>('ar');
  const [cart, setCart] = useState<CartItem[]>([{ id: 'init-1', productId: PRODUCTS[0].id, priceId: PRODUCTS[0].prices[0].id, quantity: 1 }]);
  const [customer, setCustomer] = useState({ name: '', phone: '', location: '' });
  const [aiMessage, setAiMessage] = useState('');
  const [aiResponse, setAiResponse] = useState('');
  const [isAiThinking, setIsAiThinking] = useState(false);

  const t = useMemo(() => TRANSLATIONS[lang], [lang]);

  useEffect(() => {
    document.documentElement.dir = lang === 'ar' ? 'rtl' : 'ltr';
    document.documentElement.lang = lang;
  }, [lang]);

  const toggleLanguage = () => setLang(prev => (prev === 'ar' ? 'en' : 'ar'));

  const addProductLine = () => {
    const newItem: CartItem = {
      id: Math.random().toString(36).substr(2, 9),
      productId: PRODUCTS[0].id,
      priceId: PRODUCTS[0].prices[0].id,
      quantity: 1
    };
    setCart([...cart, newItem]);
  };

  const removeProductLine = (id: string) => {
    setCart(cart.filter(item => item.id !== id));
  };

  const updateCartItem = (id: string, field: keyof CartItem, value: any) => {
    setCart(cart.map(item => {
      if (item.id === id) {
        const updated = { ...item, [field]: value };
        if (field === 'productId') {
          const product = PRODUCTS.find(p => p.id === value);
          updated.priceId = product ? product.prices[0].id : '';
        }
        return updated;
      }
      return item;
    }));
  };

  const totalOrderPrice = useMemo(() => {
    return cart.reduce((acc, item) => {
      const product = PRODUCTS.find(p => p.id === item.productId);
      const priceObj = product?.prices.find(pr => pr.id === item.priceId);
      return acc + (priceObj ? priceObj.price * item.quantity : 0);
    }, 0);
  }, [cart]);

  const handleSendOrder = () => {
    if (!customer.name || !customer.phone || !customer.location || cart.length === 0) {
      alert(t.errorFields);
      return;
    }

    let summary = '';
    cart.forEach((item, index) => {
      const product = PRODUCTS.find(p => p.id === item.productId);
      const priceObj = product?.prices.find(pr => pr.id === item.priceId);
      if (product && priceObj) {
        const prodName = lang === 'ar' ? product.titleAr : product.titleEn;
        const sizeName = lang === 'ar' ? priceObj.sizeAr : priceObj.sizeEn;
        summary += `${index + 1}. ${prodName} (${sizeName}) x ${item.quantity}\n`;
      }
    });

    const msg = `${t.whatsappOrderHeader}\n\n` +
                `${t.whatsappName} ${customer.name}\n` +
                `${t.whatsappPhone} ${customer.phone}\n` +
                `${t.whatsappLocation} ${customer.location}\n\n` +
                `${summary}\n` +
                `${t.whatsappTotal} ${totalOrderPrice} ${t.currency}`;

    window.open(`https://wa.me/${WHATSAPP_NUMBER}?text=${encodeURIComponent(msg)}`, '_blank');
  };

  const handleAiConsult = async (customMsg?: string) => {
    const messageToUse = customMsg || aiMessage;
    if (!messageToUse.trim()) return;
    setIsAiThinking(true);
    setAiResponse('');
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `
        You are a professional honey sommelier for "Honey House". 
        Language: ${lang === 'ar' ? 'Arabic' : 'English'}.
        Product Catalog: ${JSON.stringify(PRODUCTS.map(p => ({
          name: lang === 'ar' ? p.titleAr : p.titleEn,
          desc: lang === 'ar' ? p.descriptionAr : p.descriptionEn,
          benefits: lang === 'ar' ? p.benefitsAr : p.benefitsEn
        })))}
        User Query: ${messageToUse}
        Task: Provide a helpful and warm response. Recommend a specific product from our list. Keep it concise.
      `;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt
      });
      setAiResponse(response.text || '');
    } catch (error) {
      setAiResponse(lang === 'ar' ? 'عذراً، حدث خطأ.' : 'Error occurred.');
    } finally {
      setIsAiThinking(false);
    }
  };

  return (
    <div className={`min-h-screen pb-24 text-slate-900 bg-[#FEFBF6] selection:bg-amber-200`}>

      {/* Dynamic Offer Ticker */}
      <div className="bg-amber-500 text-white overflow-hidden whitespace-nowrap py-2 text-xs md:text-sm font-bold border-b border-amber-600">
         <div className="animate-marquee flex gap-12">
            <span>{t.tickerMsg1}</span>
            <span>{t.tickerMsg2}</span>
            <span>{t.tickerMsg3}</span>
            <span>{t.tickerMsg1}</span>
            <span>{t.tickerMsg2}</span>
            <span>{t.tickerMsg3}</span>
         </div>
      </div>

      {/* Navbar */}
      <nav className="sticky top-0 z-40 bg-white/80 backdrop-blur-xl border-b border-amber-100 px-6 py-4 flex justify-between items-center max-w-7xl mx-auto rounded-b-3xl shadow-sm">
        <div className="flex items-center gap-3">
           <div className="w-10 h-10 bg-amber-500 rounded-xl flex items-center justify-center p-1.5 shadow-md">
             <img src="https://imgur.com/doKxqHM.jpeg" alt="Logo" className="rounded-lg" />
           </div>
           <span className="text-2xl font-black text-amber-900 tracking-tight">{t.companyName}</span>
        </div>
        <button 
          onClick={toggleLanguage}
          className="bg-amber-50 text-amber-800 py-2 px-6 rounded-2xl text-sm font-black hover:bg-amber-100 transition-all border border-amber-100"
        >
          {lang === 'ar' ? 'English' : 'العربية'}
        </button>
      </nav>

      <div className={`max-w-6xl mx-auto px-6 mt-12 ${lang === 'en' ? 'font-inter' : 'font-cairo'}`}>

        {/* Hero */}
        <section className="text-center mb-24 relative">
          <div className="absolute top-0 left-1/2 -translate-x-1/2 w-96 h-96 bg-amber-300/10 blur-[100px] rounded-full -z-10"></div>
          <h1 className="text-6xl md:text-8xl font-black text-amber-900 mb-6 tracking-tighter">
            {t.companyName}
          </h1>
          <p className="text-2xl md:text-3xl text-amber-800/80 font-medium mb-10 max-w-3xl mx-auto leading-tight italic">
            "{t.slogan}"
          </p>
          <div className="flex flex-col md:flex-row justify-center items-center gap-4">
            <button 
              onClick={() => document.getElementById('order-form')?.scrollIntoView({ behavior: 'smooth' })}
              className="bg-amber-500 text-white px-10 py-5 rounded-[2rem] font-black text-xl shadow-xl shadow-amber-500/20 hover:scale-105 transition-transform"
            >
              {t.orderNow}
            </button>
            <div className="bg-white/50 border border-amber-200 px-8 py-4 rounded-[2rem] font-bold text-amber-800">
              {t.deliveryNote}
            </div>
          </div>
        </section>

        {/* How It Works */}
        <section className="mb-24">
          <h2 className="text-4xl font-black text-center text-amber-900 mb-12">{t.howItWorks}</h2>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
            <StepItem number="01" title={t.step1Title} desc={t.step1Desc} />
            <StepItem number="02" title={t.step2Title} desc={t.step2Desc} />
            <StepItem number="03" title={t.step3Title} desc={t.step3Desc} />
          </div>
        </section>

        {/* Products */}
        <section className="mb-24">
          <div className="flex flex-col md:flex-row justify-between items-center mb-16 gap-6">
            <h2 className="text-4xl font-black text-amber-900">{lang === 'ar' ? 'منتجاتنا المختارة' : 'Our Selection'}</h2>
            <div className="bg-amber-100 text-amber-800 px-6 py-3 rounded-2xl font-bold flex items-center gap-2">
               <span className="animate-pulse">🔥</span> {t.grandOpening}
            </div>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-12">
            {PRODUCTS.map((product) => (
              <ProductCard 
                key={product.id} 
                product={product} 
                lang={lang} 
                currency={t.currency}
                chooseSizeText={t.chooseSize}
                onOrderClick={() => document.getElementById('order-form')?.scrollIntoView({ behavior: 'smooth' })}
              />
            ))}
          </div>
        </section>

        {/* AI Section */}
        <section className="mb-24 bg-white p-12 rounded-[3.5rem] shadow-2xl shadow-amber-900/5 border border-amber-100 flex flex-col md:flex-row items-start gap-12 relative overflow-hidden">
          <div className="absolute -bottom-10 -left-10 w-48 h-48 bg-amber-50 rounded-full blur-3xl opacity-50"></div>
          <div className="w-24 h-24 bg-amber-500 rounded-[2rem] flex items-center justify-center text-5xl shadow-lg shrink-0">✨</div>
          <div className="flex-grow w-full">
            <h3 className="text-3xl font-black text-amber-900 mb-2">{t.aiAssistantTitle}</h3>
            <p className="text-xl text-amber-700 mb-6">{t.aiAssistantDesc}</p>

            <div className="flex flex-wrap gap-3 mb-6">
               {[t.aiPrompt1, t.aiPrompt2, t.aiPrompt3].map((p, i) => (
                 <button 
                  key={i}
                  onClick={() => { setAiMessage(p); handleAiConsult(p); }}
                  className="bg-amber-50 text-amber-800 px-5 py-2.5 rounded-full text-sm font-bold hover:bg-amber-200 transition-colors border border-amber-100"
                 >
                   {p}
                 </button>
               ))}
            </div>

            <div className="flex gap-4">
              <input 
