                className="flex-grow p-5 bg-slate-50 rounded-3xl border border-slate-200 focus:ring-4 focus:ring-amber-500/10 focus:border-amber-500 outline-none transition-all"
                onKeyPress={(e) => e.key === 'Enter' && handleAiConsult()}
              />
              <button 
                onClick={() => handleAiConsult()}
                disabled={isAiThinking}
                className="bg-amber-900 text-white px-8 rounded-3xl font-black hover:bg-black transition-all shadow-lg"
              >
                {isAiThinking ? '...' : lang === 'ar' ? 'اسأل' : 'Ask'}
              </button>
            </div>
            {aiResponse && (
              <div className="mt-8 p-8 bg-amber-50/50 rounded-[2rem] text-lg text-amber-900 border border-amber-100 italic leading-relaxed">
                {aiResponse}
              </div>
            )}
          </div>
        </section>

        {/* Order Form */}
        <section id="order-form" className="bg-white p-12 rounded-[4rem] shadow-3xl border border-amber-50 max-w-5xl mx-auto mb-24">
          <div className="text-center mb-16">
            <h2 className="text-5xl font-black text-amber-900 mb-4">{t.orderNow}</h2>
            <p className="text-xl text-amber-700/80">{t.fillForm}</p>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-10 mb-10">
            <InputGroup label={t.nameLabel} placeholder={t.namePlaceholder} value={customer.name} onChange={v => setCustomer({...customer, name: v})} />
            <InputGroup label={t.phoneLabel} placeholder={t.phonePlaceholder} value={customer.phone} onChange={v => setCustomer({...customer, phone: v})} />
          </div>
          <div className="mb-10">
            <InputGroup label={t.locationLabel} placeholder={t.locationPlaceholder} value={customer.location} onChange={v => setCustomer({...customer, location: v})} />
          </div>

          <div className="bg-amber-50/30 p-8 rounded-[3rem] border border-amber-100 space-y-8 mb-12">
            {cart.map((item) => (
              <CartRow 
                key={item.id}
                item={item}
                lang={lang}
                onUpdate={updateCartItem}
                onRemove={() => removeProductLine(item.id)}
                isOnly={cart.length === 1}
                t={t}
              />
            ))}
            <button onClick={addProductLine} className="w-full bg-white text-amber-800 font-black py-5 rounded-3xl border-2 border-dashed border-amber-300 hover:bg-amber-50 transition-colors text-lg">
              {t.addProduct}
            </button>
          </div>

          <div className="flex flex-col items-center">
             <div className="text-6xl font-black text-amber-600 mb-12 flex items-baseline gap-4">
               <span className="text-2xl opacity-40 font-bold">{t.total}</span>
               {totalOrderPrice} 
               <span className="text-2xl font-bold">{t.currency}</span>
             </div>
             <div className="flex flex-col sm:flex-row gap-6 w-full max-w-2xl">
               <button 
                  onClick={handleSendOrder}
                  className="flex-grow bg-amber-500 hover:bg-amber-600 text-white font-black py-6 px-10 rounded-[2.5rem] text-2xl shadow-2xl shadow-amber-500/30 transform active:scale-95 transition-all"
               >
                 {t.sendOrder}
               </button>
               <button 
                  onClick={() => window.open(`https://wa.me/${WHATSAPP_NUMBER}`, '_blank')}
                  className="bg-slate-100 text-slate-700 font-bold px-10 py-6 rounded-[2.5rem] hover:bg-slate-200 transition-all text-lg"
               >
                 {t.inquiry}
               </button>
             </div>
          </div>
        </section>

        {/* Why Us Section */}
        <section className="mb-24">
          <h2 className="text-4xl font-black text-center text-amber-900 mb-16">{t.whyChooseUs}</h2>
          <div className="grid grid-cols-2 md:grid-cols-4 gap-8">
            <TrustItem icon="🍯" title={t.natural} />
            <TrustItem icon="✅" title={t.labTested} />
            <TrustItem icon="🏠" title={t.direct} />
            <TrustItem icon="🚚" title={t.fastDelivery} />
          </div>
