        {/* FAQ */}
        <section className="mb-32 max-w-4xl mx-auto">
          <h2 className="text-4xl font-black text-center text-amber-900 mb-16">{t.faqTitle}</h2>
          <div className="space-y-6">
            {FAQS.map((faq, idx) => (
              <FaqItem key={idx} q={lang === 'ar' ? faq.ar.q : faq.en.q} a={lang === 'ar' ? faq.ar.a : faq.en.a} />
            ))}
          </div>
        </section>

      </div>

      {/* Footer */}
      <footer className="bg-amber-950 text-amber-200/60 py-24 px-8 mt-24">
        <div className="max-w-6xl mx-auto grid grid-cols-1 md:grid-cols-3 gap-16">
           <div className="flex flex-col items-center md:items-start">
             <div className="flex items-center gap-3 mb-6">
               <img src="https://imgur.com/doKxqHM.jpeg" alt="Logo" className="w-12 h-12 rounded-xl" />
