           </div>
           <div className="flex flex-col items-center md:items-end">
             <p className="text-sm opacity-50 mb-4">© {new Date().getFullYear()} Honey House. UAE Premium Honey.</p>
             <div className="flex gap-4">
                <span className="w-10 h-10 bg-amber-900 rounded-full flex items-center justify-center">FB</span>
                <span className="w-10 h-10 bg-amber-900 rounded-full flex items-center justify-center">IG</span>
             </div>
           </div>
        </div>
      </footer>

      {/* Mobile Sticky Bar */}
      <div className="fixed bottom-8 left-8 right-8 md:hidden z-50">
         <div className="bg-white/95 backdrop-blur-2xl p-5 rounded-[2.5rem] shadow-3xl border border-amber-100 flex justify-between items-center ring-1 ring-black/5">
            <div>
              <p className="text-[10px] font-black text-amber-800/40 uppercase tracking-widest">{t.total}</p>
              <p className="text-2xl font-black text-amber-600 leading-none">{totalOrderPrice} {t.currency}</p>
            </div>
            <button 
              onClick={() => document.getElementById('order-form')?.scrollIntoView({ behavior: 'smooth' })}
              className="bg-amber-500 text-white px-8 py-4 rounded-3xl font-black shadow-xl shadow-amber-500/20 active:scale-95 transition-all"
            >
