         <img src={product.image} alt={product.titleEn} className="max-h-full w-auto object-contain group-hover:scale-110 transition-transform duration-1000 z-10 drop-shadow-2xl" />
      </div>
      <div className="p-12 flex-grow flex flex-col">
        <div className="flex flex-wrap gap-2 mb-6">
           {(lang === 'ar' ? product.benefitsAr : product.benefitsEn).map((b: string, i: number) => (
             <span key={i} className="bg-amber-100/60 text-amber-900 text-[11px] font-black px-4 py-2 rounded-full uppercase tracking-widest border border-amber-200/50">{b}</span>
           ))}
        </div>
        <h3 className="text-3xl font-black text-amber-950 mb-4 leading-tight">{lang === 'ar' ? product.titleAr : product.titleEn}</h3>
        <p className="text-amber-800/60 text-lg mb-10 line-clamp-2 leading-relaxed font-medium">{lang === 'ar' ? product.descriptionAr : product.descriptionEn}</p>

        {product.prices.length > 1 && (
          <div className="mb-10">
            <p className="text-[11px] font-black text-amber-300 uppercase tracking-[0.2em] mb-4">{chooseSizeText}</p>
            <div className="flex flex-wrap gap-3">
              {product.prices.map((p: any, i: number) => (
                <button 
                  key={p.id} 
                  onClick={() => setSizeIdx(i)}
                  className={`px-7 py-3.5 rounded-2xl text-xs font-black transition-all ${sizeIdx === i ? 'bg-amber-950 text-white shadow-lg scale-105' : 'bg-slate-50 text-amber-900 border border-slate-200 hover:border-amber-400'}`}
                >
                  {lang === 'ar' ? p.sizeAr : p.sizeEn}
                </button>
              ))}
            </div>
          </div>
        )}

        <div className="mt-auto pt-10 flex justify-between items-center border-t border-amber-50">
          <div className="flex items-baseline gap-1.5">
            <span className="text-5xl font-black text-amber-600 tracking-tighter leading-none">{current.price}</span>
            <span className="text-lg font-black text-amber-300 uppercase">{currency}</span>
          </div>
          <button onClick={onOrderClick} className="bg-amber-500 text-white px-10 py-5 rounded-[2rem] font-black hover:bg-amber-600 transition-all shadow-xl shadow-amber-500/20 active:scale-95">
             {lang === 'ar' ? 'اطلب الآن' : 'Order Now'}
          </button>
        </div>
      </div>
    </div>
  );
};

const InputGroup = ({ label, placeholder, value, onChange }: any) => (
  <div className="space-y-4">
    <label className="text-[11px] font-black text-amber-900/40 uppercase tracking-[0.3em] ml-2">{label}</label>
    <input 
      type="text"
      value={value}
      onChange={e => onChange(e.target.value)}
      className="w-full p-7 bg-slate-50 rounded-[2.5rem] border border-slate-100 focus:ring-[12px] focus:ring-amber-500/5 focus:border-amber-500 outline-none transition-all placeholder:text-slate-300 text-xl font-bold text-amber-950"
      placeholder={placeholder}
    />
  </div>
);

const CartRow = ({ item, lang, onUpdate, onRemove, isOnly, t }: any) => {
  const prod = PRODUCTS.find(p => p.id === item.productId);
  return (
    <div className="flex flex-col lg:flex-row items-center gap-8 bg-white p-8 rounded-[3rem] shadow-sm border border-amber-100/30">
      <select 
        value={item.productId} 
        onChange={e => onUpdate(item.id, 'productId', e.target.value)}
        className="flex-grow p-5 bg-slate-50 rounded-[1.5rem] outline-none text-amber-950 font-black w-full lg:w-auto appearance-none cursor-pointer border-2 border-transparent focus:border-amber-300 transition-all text-lg"
      >
        {PRODUCTS.map(p => <option key={p.id} value={p.id}>{lang === 'ar' ? p.titleAr : p.titleEn}</option>)}
      </select>
      <select 
        value={item.priceId} 
        onChange={e => onUpdate(item.id, 'priceId', e.target.value)}
        className="w-full lg:w-64 p-5 bg-slate-50 rounded-[1.5rem] outline-none text-amber-800 font-bold border-2 border-transparent focus:border-amber-300 transition-all text-lg"
      >
        {prod?.prices.map(pr => <option key={pr.id} value={pr.id}>{lang === 'ar' ? pr.sizeAr : pr.sizeEn} ({pr.price} {t.currency})</option>)}
      </select>
      <div className="flex items-center gap-6 w-full lg:w-auto">
        <div className="flex items-center bg-slate-50 rounded-[1.5rem] px-4">
            <button onClick={() => onUpdate(item.id, 'quantity', Math.max(1, item.quantity - 1))} className="p-4 text-amber-900 font-black text-2xl">-</button>
            <input 
              type="number" 
              min="1" 
              value={item.quantity} 
              onChange={e => onUpdate(item.id, 'quantity', parseInt(e.target.value) || 1)}
              className="w-16 p-4 bg-transparent text-center font-black outline-none text-xl"
            />
            <button onClick={() => onUpdate(item.id, 'quantity', item.quantity + 1)} className="p-4 text-amber-900 font-black text-2xl">+</button>
        </div>
        {!isOnly && (
          <button onClick={onRemove} className="bg-red-50 text-red-500 w-16 h-16 rounded-[1.5rem] flex items-center justify-center hover:bg-red-500 hover:text-white transition-all shadow-sm">
             <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
               <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" />
             </svg>
          </button>
        )}
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { Language, CartItem } from './types';
import { PRODUCTS, TRANSLATIONS, WHATSAPP_NUMBER, INSTAGRAM_URL, FAQS, MOCK_REVIEWS } from './constants';
import { GoogleGenAI } from "@google/genai";

const App: React.FC = () => {
  const [lang, setLang] = useState<Language>('ar');
  const [cart, setCart] = useState<CartItem[]>([{ id: 'init-1', productId: PRODUCTS[0].id, priceId: PRODUCTS[0].prices[0].id, quantity: 1 }]);
  const [customer, setCustomer] = useState({ name: '', phone: '', location: '' });
  const [aiMessage, setAiMessage] = useState('');
  const [aiResponse, setAiResponse] = useState('');
  const [isAiThinking, setIsAiThinking] = useState(false);

  // Reviews State
  const [showReviews, setShowReviews] = useState(false);
  const [localReviews, setLocalReviews] = useState<any[]>([]);
  const [isReviewFormOpen, setIsReviewFormOpen] = useState(false);
  const [newReview, setNewReview] = useState({ name: '', comment: '', rating: 5 });

  const t = useMemo(() => TRANSLATIONS[lang], [lang]);

  // Load reviews from localStorage
  useEffect(() => {
    const saved = localStorage.getItem('honey_house_reviews');
    if (saved) {
      try {
        setLocalReviews(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse local reviews");
      }
    }
  }, []);

  useEffect(() => {
    document.documentElement.dir = lang === 'ar' ? 'rtl' : 'ltr';
    document.documentElement.lang = lang;
  }, [lang]);

  const toggleLanguage = () => setLang(prev => (prev === 'ar' ? 'en' : 'ar'));

  const addProductLine = () => {
    const newItem: CartItem = {
      id: Math.random().toString(36).substr(2, 9),
      productId: PRODUCTS[0].id,
      priceId: PRODUCTS[0].prices[0].id,
      quantity: 1
    };
    setCart([...cart, newItem]);
  };

  const removeProductLine = (id: string) => {
    setCart(cart.filter(item => item.id !== id));
  };

  const updateCartItem = (id: string, field: keyof CartItem, value: any) => {
    setCart(cart.map(item => {
      if (item.id === id) {
        const updated = { ...item, [field]: value };
        if (field === 'productId') {
          const product = PRODUCTS.find(p => p.id === value);
          updated.priceId = product ? product.prices[0].id : '';
        }
        return updated;
      }
      return item;
    }));
  };

  const totalOrderPrice = useMemo(() => {
    return cart.reduce((acc, item) => {
      const product = PRODUCTS.find(p => p.id === item.productId);
      const priceObj = product?.prices.find(pr => pr.id === item.priceId);
      return acc + (priceObj ? priceObj.price * item.quantity : 0);
    }, 0);
  }, [cart]);

  const handleSendOrder = () => {
    if (!customer.name || !customer.phone || !customer.location || cart.length === 0) {
      alert(t.errorFields);
      return;
    }

    let summary = '';
    cart.forEach((item, index) => {
      const product = PRODUCTS.find(p => p.id === item.productId);
      const priceObj = product?.prices.find(pr => pr.id === item.priceId);
      if (product && priceObj) {
        const prodName = lang === 'ar' ? product.titleAr : product.titleEn;
        const sizeName = lang === 'ar' ? priceObj.sizeAr : priceObj.sizeEn;
        summary += `${index + 1}. ${prodName} (${sizeName}) x ${item.quantity}\n`;
      }
    });

    const msg = `${t.whatsappOrderHeader}\n\n` +
                `${t.whatsappName} ${customer.name}\n` +
                `${t.whatsappPhone} ${customer.phone}\n` +
                `${t.whatsappLocation} ${customer.location}\n\n` +
                `${summary}\n` +
                `${t.whatsappTotal} ${totalOrderPrice} ${t.currency}`;

    window.open(`https://wa.me/${WHATSAPP_NUMBER}?text=${encodeURIComponent(msg)}`, '_blank');
  };

  const handleAiConsult = async (customMsg?: string) => {
    const messageToUse = customMsg || aiMessage;
    if (!messageToUse.trim()) return;
    setIsAiThinking(true);
    setAiResponse('');
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `
        You are the Head Honey Sommelier at "Honey House". 
        Language: ${lang === 'ar' ? 'Arabic' : 'English'}.
        Products: ${JSON.stringify(PRODUCTS.map(p => ({
          name: lang === 'ar' ? p.titleAr : p.titleEn,
          desc: lang === 'ar' ? p.descriptionAr : p.descriptionEn,
          benefits: lang === 'ar' ? p.benefitsAr : p.benefitsEn
        })))}
        User Query: ${messageToUse}
        Task: Be an expert. Recommend ONE specific product. Keep it warm, elegant, and short.
      `;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt
      });
      setAiResponse(response.text || '');
    } catch (error) {
      setAiResponse(lang === 'ar' ? 'عذراً، حدث خطأ.' : 'Error occurred.');
    } finally {
      setIsAiThinking(false);
    }
  };

  const scrollToSection = (id: string) => {
    if (id === 'reviews-section') setShowReviews(true);

    // Small timeout to ensure visibility state has updated if needed
    setTimeout(() => {
      const element = document.getElementById(id);
      if (element) {
        element.scrollIntoView({ behavior: 'smooth' });
      }
    }, 50);
  };

  const handleSubmitReview = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newReview.name || !newReview.comment) return;

    const reviewObj = {
      ...newReview,
      id: Date.now(),
      date: new Date().toLocaleDateString(),
      isLocal: true
    };

    const updated = [reviewObj, ...localReviews];
    setLocalReviews(updated);
    localStorage.setItem('honey_house_reviews', JSON.stringify(updated));
    setNewReview({ name: '', comment: '', rating: 5 });
    setIsReviewFormOpen(false);
    setShowReviews(true);
  };

  const allReviews = useMemo(() => {
    const formattedLocal = localReviews.map(r => ({
      ar: { name: r.name, comment: r.comment },
      en: { name: r.name, comment: r.comment },
      rating: r.rating
    }));
    return [...formattedLocal, ...MOCK_REVIEWS];
  }, [localReviews]);

  return (
    <div className={`min-h-screen pb-24 text-slate-900 bg-[#FEFBF6] selection:bg-amber-200 antialiased`}>

      {/* Dynamic Offer Ticker */}
      <div className="bg-amber-500 text-white overflow-hidden whitespace-nowrap py-2 text-xs md:text-sm font-bold border-b border-amber-600 shadow-sm relative z-50">
         <div className="animate-marquee flex gap-12">
            <span>{t.tickerMsg1}</span>
            <span>{t.tickerMsg2}</span>
            <span>{t.tickerMsg3}</span>
            <span>{t.tickerMsg1}</span>
            <span>{t.tickerMsg2}</span>
            <span>{t.tickerMsg3}</span>
         </div>
      </div>

      {/* Navbar */}
      <nav className="sticky top-0 z-40 bg-white/70 backdrop-blur-2xl border-b border-amber-100/50 px-6 py-4 flex justify-between items-center max-w-7xl mx-auto rounded-b-[2.5rem] shadow-sm">
        <div className="flex items-center gap-3">
           <div className="w-11 h-11 bg-gradient-to-tr from-amber-600 to-amber-400 rounded-2xl flex items-center justify-center p-1.5 shadow-lg shadow-amber-500/20">
             <img src="https://imgur.com/doKxqHM.jpeg" alt="Logo" className="rounded-xl brightness-110" />
           </div>
           <span className="text-2xl font-black text-amber-900 tracking-tight">{t.companyName}</span>
        </div>
        <button 
          onClick={toggleLanguage}
          className="bg-white/50 text-amber-900 py-2.5 px-6 rounded-2xl text-sm font-black hover:bg-amber-500 hover:text-white transition-all border border-amber-200/50 shadow-sm"
        >
          {lang === 'ar' ? 'English' : 'العربية'}
        </button>
      </nav>

      <div className={`max-w-6xl mx-auto px-6 mt-16 ${lang === 'en' ? 'font-inter' : 'font-cairo'}`}>

        {/* Hero */}
        <section className="text-center mb-12 relative">
          <div className="absolute top-0 left-1/2 -translate-x-1/2 w-full max-w-2xl h-96 bg-amber-400/5 blur-[120px] rounded-full -z-10 animate-pulse"></div>
          <h1 className="text-6xl md:text-8xl font-black text-amber-950 mb-6 tracking-tighter leading-none">
            {t.companyName}
          </h1>
          <p className="text-2xl md:text-3xl text-amber-800/70 font-medium mb-10 max-w-3xl mx-auto leading-tight italic">
            "{t.slogan}"
          </p>
          <div className="flex flex-col md:flex-row justify-center items-center gap-6">
            <button 
              onClick={() => scrollToSection('order-form')}
              className="bg-amber-500 text-white px-12 py-5 rounded-[2.5rem] font-black text-2xl shadow-2xl shadow-amber-500/40 hover:scale-105 active:scale-95 transition-all"
            >
              {t.orderNow}
            </button>
            <div className="flex items-center gap-2 bg-amber-50 border border-amber-200 px-8 py-4 rounded-[2.5rem] font-black text-amber-800 shadow-sm">
              <span className="text-xl">📍</span> {t.deliveryNote}
            </div>
          </div>
        </section>

        {/* Trust Stats Bar */}
        <section className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-24 px-4">
           <TrustStat 
              icon="⭐" 
              label={lang === 'ar' ? '4.9 تقييم العملاء' : '4.9 Customer Rating'} 
              onClick={() => scrollToSection('reviews-section')}
           />
           <TrustStat icon="🚛" label={lang === 'ar' ? 'توصيل خلال 24 ساعة' : '24h UAE Delivery'} />
           <TrustStat icon="💎" label={lang === 'ar' ? 'عسل طبيعي 100%' : '100% Pure Honey'} />
           <TrustStat icon="✅" label={lang === 'ar' ? 'مفحوص مخبرياً' : 'Lab Certified'} />
        </section>

        {/* AI Section (Sommelier) */}
        <section className="mb-24 bg-gradient-to-br from-white to-amber-50/30 p-12 rounded-[4rem] shadow-2xl shadow-amber-900/5 border border-amber-100 flex flex-col items-center gap-10 relative overflow-hidden group">
          <div className="absolute top-0 right-0 w-64 h-64 bg-amber-200/10 rounded-full blur-3xl -z-0"></div>
          <div className="w-28 h-28 bg-gradient-to-tr from-amber-600 to-amber-400 rounded-[2.5rem] flex items-center justify-center text-6xl shadow-2xl shadow-amber-500/30 shrink-0 transform group-hover:rotate-6 transition-transform">✨</div>

          <div className="w-full text-center max-w-3xl">
            <h3 className="text-4xl font-black text-amber-950 mb-3 tracking-tight">{t.aiAssistantTitle}</h3>
            <p className="text-xl text-amber-700/80 mb-10 font-medium">{t.aiAssistantDesc}</p>

            <div className="flex flex-wrap justify-center gap-3 mb-10">
               {[t.aiPrompt1, t.aiPrompt2, t.aiPrompt3].map((p, i) => (
                 <button 
                  key={i}
                  onClick={() => { setAiMessage(p); handleAiConsult(p); }}
                  className="bg-white text-amber-900 px-7 py-3 rounded-full text-sm font-black hover:bg-amber-500 hover:text-white transition-all border border-amber-200 shadow-sm"
                 >
                   {p}
                 </button>
               ))}
            </div>

            <div className="flex flex-col md:flex-row gap-4 max-w-2xl mx-auto bg-white p-3 rounded-[2.5rem] shadow-xl border border-amber-100">
              <input 
                type="text"
                value={aiMessage}
                onChange={(e) => setAiMessage(e.target.value)}
                placeholder={t.aiPlaceholder}
                className="flex-grow p-5 bg-transparent rounded-3xl outline-none text-lg font-bold placeholder:text-slate-300"
                onKeyPress={(e) => e.key === 'Enter' && handleAiConsult()}
              />
              <button 
                onClick={() => handleAiConsult()}
                disabled={isAiThinking}
                className="bg-amber-950 text-white px-10 py-5 rounded-[2rem] font-black hover:bg-amber-500 transition-all shadow-lg active:scale-95 disabled:opacity-50"
              >
                {isAiThinking ? (
                  <div className="flex gap-1">
                    <span className="w-1.5 h-1.5 bg-white rounded-full animate-bounce"></span>
                    <span className="w-1.5 h-1.5 bg-white rounded-full animate-bounce [animation-delay:0.2s]"></span>
                    <span className="w-1.5 h-1.5 bg-white rounded-full animate-bounce [animation-delay:0.4s]"></span>
                  </div>
                ) : (lang === 'ar' ? 'استشر الخبير' : 'Consult')}
              </button>
            </div>

            {aiResponse && (
              <div className="mt-12 p-10 bg-white/50 backdrop-blur-md rounded-[3rem] text-xl text-amber-950 border border-amber-200/50 italic leading-relaxed shadow-inner animate-in fade-in slide-in-from-bottom-4 duration-500">
                "{aiResponse}"
              </div>
            )}
          </div>
        </section>

        {/* Products */}
        <section className="mb-32">
          <div className="flex flex-col md:flex-row justify-between items-end mb-16 gap-8">
            <div>
              <h2 className="text-5xl font-black text-amber-950 mb-4">{lang === 'ar' ? 'تشكيلتنا الفاخرة' : 'Our Luxury Selection'}</h2>
              <p className="text-xl text-amber-700/70 font-medium">{lang === 'ar' ? 'أجود أنواع العسل المصري المختارة بعناية.' : 'The finest Egyptian honey varieties, handpicked for quality.'}</p>
            </div>
            <div className="bg-amber-100/50 backdrop-blur-sm text-amber-800 px-8 py-4 rounded-[2rem] font-black flex items-center gap-3 border border-amber-200">
               <span className="text-2xl animate-pulse">🎉</span> {t.grandOpening}
            </div>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-12">
            {PRODUCTS.map((product) => (
              <ProductCard 
                key={product.id} 
                product={product} 
                lang={lang} 
                currency={t.currency}
                chooseSizeText={t.chooseSize}
                onOrderClick={() => scrollToSection('order-form')}
              />
            ))}
          </div>
        </section>

        {/* Order Form */}
        <section id="order-form" className="bg-white p-16 rounded-[5rem] shadow-[0_50px_100px_-20px_rgba(139,69,19,0.1)] border border-amber-50 max-w-5xl mx-auto mb-32 relative scroll-mt-24">
          <div className="absolute -top-12 left-1/2 -translate-x-1/2 bg-amber-500 text-white w-24 h-24 rounded-full flex items-center justify-center text-4xl shadow-xl shadow-amber-500/30">📦</div>
          <div className="text-center mb-16 pt-6">
            <h2 className="text-5xl font-black text-amber-950 mb-4">{t.orderNow}</h2>
            <p className="text-xl text-amber-700/80">{t.fillForm}</p>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-10 mb-10">
            <InputGroup label={t.nameLabel} placeholder={t.namePlaceholder} value={customer.name} onChange={v => setCustomer({...customer, name: v})} />
            <InputGroup label={t.phoneLabel} placeholder={t.phonePlaceholder} value={customer.phone} onChange={v => setCustomer({...customer, phone: v})} />
          </div>
          <div className="mb-10">
            <InputGroup label={t.locationLabel} placeholder={t.locationPlaceholder} value={customer.location} onChange={v => setCustomer({...customer, location: v})} />
          </div>

          <div className="bg-slate-50/50 p-10 rounded-[3.5rem] border border-slate-100 space-y-8 mb-16">
            {cart.map((item) => (
              <CartRow 
                key={item.id}
                item={item}
                lang={lang}
                onUpdate={updateCartItem}
                onRemove={() => removeProductLine(item.id)}
                isOnly={cart.length === 1}
                t={t}
              />
            ))}
            <button onClick={addProductLine} className="w-full bg-white text-amber-900 font-black py-6 rounded-[2rem] border-2 border-dashed border-amber-200 hover:border-amber-500 hover:bg-amber-50 transition-all text-xl shadow-sm">
              {t.addProduct}
            </button>
          </div>

          <div className="flex flex-col items-center">
             <div className="text-7xl font-black text-amber-600 mb-16 flex items-baseline gap-4">
               <span className="text-2xl opacity-40 font-bold uppercase tracking-widest">{t.total}</span>
               {totalOrderPrice} 
               <span className="text-2xl font-black">{t.currency}</span>
             </div>
             <div className="flex flex-col sm:flex-row gap-8 w-full max-w-3xl">
               <button 
                  onClick={handleSendOrder}
                  className="flex-grow bg-amber-500 hover:bg-amber-600 text-white font-black py-7 px-12 rounded-[2.5rem] text-3xl shadow-2xl shadow-amber-500/40 transform active:scale-95 hover:-translate-y-1 transition-all"
               >
                 {t.sendOrder}
               </button>
               <button 
                  onClick={() => window.open(`https://wa.me/${WHATSAPP_NUMBER}`, '_blank')}
                  className="bg-slate-900 text-white font-black px-12 py-7 rounded-[2.5rem] hover:bg-black transition-all text-xl shadow-xl shadow-slate-900/10"
               >
                 {t.inquiry}
               </button>
             </div>
          </div>
        </section>

        {/* Reviews Section */}
        <section id="reviews-section" className="mb-32 scroll-mt-24">
          <div className="flex flex-col md:flex-row justify-between items-center mb-10 gap-6">
            <button 
              onClick={() => setShowReviews(!showReviews)}
              className="text-4xl font-black text-amber-950 flex items-center gap-4 hover:opacity-70 transition-opacity"
            >
              {t.reviewsTitle}
              <span className={`text-2xl transition-transform duration-500 ${showReviews ? 'rotate-180' : ''}`}>▼</span>
            </button>
            <button 
              onClick={() => setIsReviewFormOpen(!isReviewFormOpen)}
              className="bg-amber-100 text-amber-800 px-8 py-4 rounded-[2rem] font-black border border-amber-200 hover:bg-amber-200 transition-all shadow-sm"
            >
              {t.leaveReview} ✨
            </button>
          </div>

          {/* New Review Form */}
