        <div className="mb-12">
           <p className="text-[11px] font-black text-amber-400 uppercase tracking-[0.3em] mb-6">{chooseSizeText}</p>
           <div className="flex flex-wrap gap-4">
              {product.prices.map((p: any, i: number) => (
                <button 
                  key={p.id} 
                  onClick={() => setSizeIdx(i)}
                  className={`px-8 py-4 rounded-2xl text-sm font-black transition-all duration-300 ${sizeIdx === i ? 'bg-amber-950 text-white shadow-2xl scale-105 ring-8 ring-amber-500/5' : 'bg-white text-amber-900 border border-amber-100 hover:border-amber-400'}`}
