};

const InputGroup = ({ label, placeholder, value, onChange }: any) => (
  <div className="space-y-4">
    <label className="text-[11px] font-black text-amber-900/40 uppercase tracking-[0.3em] ml-2">{label}</label>
    <input 
      type="text"
      required
      value={value}
      onChange={e => onChange(e.target.value)}
      className="w-full p-7 bg-slate-50 rounded-[2.5rem] border border-slate-100 focus:ring-[12px] focus:ring-amber-500/5 focus:border-amber-500 outline-none transition-all placeholder:text-slate-300 text-xl font-bold text-amber-950"
      placeholder={placeholder}
    />
  </div>
);

const CartRow = ({ item, lang, onUpdate, onRemove, isOnly, t }: any) => {
  const prod = PRODUCTS.find(p => p.id === item.productId);
  return (
    <div className="flex flex-col lg:flex-row items-center gap-8 bg-white p-8 rounded-[3rem] shadow-sm border border-amber-100/30">
      <select 
        value={item.productId} 
        onChange={e => onUpdate(item.id, 'productId', e.target.value)}
        className="flex-grow p-5 bg-slate-50 rounded-[1.5rem] outline-none text-amber-950 font-black w-full lg:w-auto appearance-none cursor-pointer border-2 border-transparent focus:border-amber-300 transition-all text-lg"
      >
        {PRODUCTS.map(p => <option key={p.id} value={p.id}>{lang === 'ar' ? p.titleAr : p.titleEn}</option>)}
      </select>
      <select 
        value={item.priceId} 
        onChange={e => onUpdate(item.id, 'priceId', e.target.value)}
        className="w-full lg:w-64 p-5 bg-slate-50 rounded-[1.5rem] outline-none text-amber-800 font-bold border-2 border-transparent focus:border-amber-300 transition-all text-lg"
      >
        {prod?.prices.map(pr => <option key={pr.id} value={pr.id}>{lang === 'ar' ? pr.sizeAr : pr.sizeEn} ({pr.price} {t.currency})</option>)}
      </select>
      <div className="flex items-center gap-6 w-full lg:w-auto">
        <div className="flex items-center bg-slate-50 rounded-[1.5rem] px-4">
            <button onClick={() => onUpdate(item.id, 'quantity', Math.max(1, item.quantity - 1))} className="p-4 text-amber-900 font-black text-2xl">-</button>
            <input 
              type="number" 
              min="1" 
              value={item.quantity} 
              onChange={e => onUpdate(item.id, 'quantity', parseInt(e.target.value) || 1)}
              className="w-16 p-4 bg-transparent text-center font-black outline-none text-xl"
            />
            <button onClick={() => onUpdate(item.id, 'quantity', item.quantity + 1)} className="p-4 text-amber-900 font-black text-2xl">+</button>
        </div>
        {!isOnly && (
          <button onClick={onRemove} className="bg-red-50 text-red-500 w-16 h-16 rounded-[1.5rem] flex items-center justify-center hover:bg-red-500 hover:text-white transition-all shadow-sm">
             <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
               <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" />
             </svg>
          </button>
        )}
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { Language, CartItem } from './types';
import { PRODUCTS, TRANSLATIONS, WHATSAPP_NUMBER, INSTAGRAM_URL, FAQS, MOCK_REVIEWS } from './constants';
import { GoogleGenAI } from "@google/genai";

const App: React.FC = () => {
  const [lang, setLang] = useState<Language>('ar');
  const [cart, setCart] = useState<CartItem[]>([]);
  const [customer, setCustomer] = useState({ name: '', phone: '', location: '' });
  const [aiMessage, setAiMessage] = useState('');
  const [aiResponse, setAiResponse] = useState('');
  const [isAiThinking, setIsAiThinking] = useState(false);

  const [showReviews, setShowReviews] = useState(false);
  const [localReviews, setLocalReviews] = useState<any[]>([]);
  const [isReviewFormOpen, setIsReviewFormOpen] = useState(false);
  const [newReview, setNewReview] = useState({ name: '', comment: '', rating: 5 });
  const [addedNotify, setAddedNotify] = useState<string | null>(null);

  const t = useMemo(() => TRANSLATIONS[lang], [lang]);

  useEffect(() => {
    const saved = localStorage.getItem('honey_house_reviews');
    if (saved) {
      try { setLocalReviews(JSON.parse(saved)); } catch (e) {}
    }
    // Set initial cart if empty
    if (cart.length === 0) {
      setCart([{ id: 'init-1', productId: PRODUCTS[0].id, priceId: PRODUCTS[0].prices[0].id, quantity: 1 }]);
    }
  }, []);

  useEffect(() => {
    document.documentElement.dir = lang === 'ar' ? 'rtl' : 'ltr';
    document.documentElement.lang = lang;
  }, [lang]);

  const toggleLanguage = () => setLang(prev => (prev === 'ar' ? 'en' : 'ar'));

  const addToBasket = (productId: string, priceId: string) => {
    const newItem: CartItem = {
      id: Math.random().toString(36).substr(2, 9),
      productId,
      priceId,
      quantity: 1
    };
    // If initial dummy item exists and matches, don't just add, or if cart is "emptyish"
    if (cart.length === 1 && cart[0].id === 'init-1' && cart[0].quantity === 1 && cart[0].productId === PRODUCTS[0].id) {
       setCart([newItem]);
    } else {
       setCart([...cart, newItem]);
    }

    const prod = PRODUCTS.find(p => p.id === productId);
    setAddedNotify(lang === 'ar' ? `تمت إضافة ${prod?.titleAr} للسلة` : `Added ${prod?.titleEn} to basket`);
    setTimeout(() => setAddedNotify(null), 3000);
  };

  const removeProductLine = (id: string) => {
    setCart(cart.filter(item => item.id !== id));
  };

  const updateCartItem = (id: string, field: keyof CartItem, value: any) => {
    setCart(cart.map(item => {
      if (item.id === id) {
        const updated = { ...item, [field]: value };
        if (field === 'productId') {
          const product = PRODUCTS.find(p => p.id === value);
          updated.priceId = product ? product.prices[0].id : '';
        }
        return updated;
      }
      return item;
    }));
  };

  const totalOrderPrice = useMemo(() => {
    return cart.reduce((acc, item) => {
      const product = PRODUCTS.find(p => p.id === item.productId);
      const priceObj = product?.prices.find(pr => pr.id === item.priceId);
      return acc + (priceObj ? priceObj.price * item.quantity : 0);
    }, 0);
  }, [cart]);

  const handleSendOrder = () => {
    if (!customer.name || !customer.phone || !customer.location || cart.length === 0) {
      alert(t.errorFields);
      return;
    }
    let summary = '';
    cart.forEach((item, index) => {
      const product = PRODUCTS.find(p => p.id === item.productId);
      const priceObj = product?.prices.find(pr => pr.id === item.priceId);
      if (product && priceObj) {
        summary += `${index + 1}. ${lang === 'ar' ? product.titleAr : product.titleEn} (${lang === 'ar' ? priceObj.sizeAr : priceObj.sizeEn}) x ${item.quantity}\n`;
      }
    });
    const msg = `${t.whatsappOrderHeader}\n\n${t.whatsappName} ${customer.name}\n${t.whatsappPhone} ${customer.phone}\n${t.whatsappLocation} ${customer.location}\n\n${summary}\n${t.whatsappTotal} ${totalOrderPrice} ${t.currency}`;
    window.open(`https://wa.me/${WHATSAPP_NUMBER}?text=${encodeURIComponent(msg)}`, '_blank');
  };

  const handleAiConsult = async (customMsg?: string) => {
    const messageToUse = customMsg || aiMessage;
    if (!messageToUse.trim()) return;
    setIsAiThinking(true);
    setAiResponse('');
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `Sommelier advice for Honey House. Language: ${lang}. User: ${messageToUse}. Short and elegant.`;
      const response = await ai.models.generateContent({ model: 'gemini-3-flash-preview', contents: prompt });
      setAiResponse(response.text || '');
    } catch (e) { setAiResponse('Error.'); } finally { setIsAiThinking(false); }
  };

  const scrollToSection = (id: string) => {
    if (id === 'reviews-section') setShowReviews(true);
    setTimeout(() => {
      const el = document.getElementById(id);
      if (el) el.scrollIntoView({ behavior: 'smooth' });
    }, 50);
  };

  const allReviews = useMemo(() => {
    const local = localReviews.map(r => ({ ar: { name: r.name, comment: r.comment }, en: { name: r.name, comment: r.comment }, rating: r.rating }));
    return [...local, ...MOCK_REVIEWS];
  }, [localReviews]);

  return (
    <div className="min-h-screen text-slate-900 bg-[#FEFBF6] selection:bg-amber-200 antialiased font-primary">
      {/* Added Notification Toast */}
      {addedNotify && (
        <div className="fixed top-24 left-1/2 -translate-x-1/2 z-[100] bg-amber-600 text-white px-8 py-4 rounded-full font-black shadow-2xl animate-in fade-in slide-in-from-top-4 duration-300 flex items-center gap-3">
          <span className="text-xl">✅</span> {addedNotify}
        </div>
      )}

      {/* Ticker */}
      <div className="bg-amber-500 text-white py-2 text-xs md:text-sm font-bold border-b border-amber-600 relative z-50 overflow-hidden">
         <div className="animate-marquee flex gap-12 whitespace-nowrap">
            <span>{t.tickerMsg1}</span><span>{t.tickerMsg2}</span><span>{t.tickerMsg3}</span>
            <span>{t.tickerMsg1}</span><span>{t.tickerMsg2}</span><span>{t.tickerMsg3}</span>
         </div>
      </div>

      {/* Navbar */}
      <nav className="sticky top-0 z-40 bg-white/80 backdrop-blur-xl border-b border-amber-100/50 px-6 py-4 flex justify-between items-center max-w-7xl mx-auto rounded-b-[2.5rem] shadow-sm">
        <div className="flex items-center gap-3">
           <div className="w-10 h-10 bg-amber-500 rounded-xl flex items-center justify-center p-1 shadow-lg">
             <img src="https://imgur.com/doKxqHM.jpeg" alt="Logo" className="rounded-lg" />
           </div>
           <span className="text-xl font-black text-amber-900">{t.companyName}</span>
        </div>
        <div className="flex gap-4">
           <button onClick={toggleLanguage} className="bg-amber-50 text-amber-900 py-2 px-4 rounded-xl text-xs font-black border border-amber-100 uppercase">{lang === 'ar' ? 'English' : 'العربية'}</button>
        </div>
      </nav>

      <div className="max-w-7xl mx-auto px-6 mt-12">
        {/* Hero Compact */}
        <section className="text-center mb-16 relative">
          <h1 className="text-5xl md:text-7xl font-black text-amber-950 mb-4 tracking-tighter leading-none">{t.companyName}</h1>
          <p className="text-xl text-amber-800/70 font-medium italic mb-8">"{t.slogan}"</p>
          <div className="flex justify-center gap-4">
             <button onClick={() => scrollToSection('products-grid')} className="bg-amber-500 text-white px-8 py-4 rounded-2xl font-black text-lg shadow-xl hover:scale-105 transition-all">{t.orderNow}</button>
             <div className="bg-white border border-amber-100 px-6 py-4 rounded-2xl font-bold text-amber-800 text-sm hidden sm:flex items-center gap-2">📍 {t.deliveryNote}</div>
          </div>
        </section>

        {/* Products Compact Grid */}
        <section id="products-grid" className="mb-24 scroll-mt-24">
          <div className="flex flex-col md:flex-row justify-between items-end mb-10 gap-4">
            <h2 className="text-3xl font-black text-amber-950">{lang === 'ar' ? 'منتجاتنا المختارة' : 'Our Quick Selection'}</h2>
            <p className="text-amber-700/60 font-medium text-sm">{lang === 'ar' ? 'مرر الماوس للتفاصيل' : 'Hover for details & quick add'}</p>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-8">
            {PRODUCTS.map(p => (
              <QuickProductCard 
                key={p.id} 
                product={p} 
                lang={lang} 
                currency={t.currency} 
                onAdd={addToBasket}
              />
            ))}
          </div>
        </section>

        {/* AI & Trust Stats in one row */}
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 mb-24">
           {/* AI Sommelier */}
           <div className="lg:col-span-2 bg-amber-950 text-amber-50 p-10 rounded-[3rem] shadow-2xl relative overflow-hidden group">
              <div className="relative z-10">
                <h3 className="text-2xl font-black mb-2 flex items-center gap-2">✨ {t.aiAssistantTitle}</h3>
                <p className="opacity-70 text-sm mb-6">{t.aiAssistantDesc}</p>
                <div className="flex flex-col sm:flex-row gap-2 bg-white/10 p-2 rounded-2xl backdrop-blur-md">
                   <input 
                    type="text" value={aiMessage} onChange={e => setAiMessage(e.target.value)}
                    placeholder={t.aiPlaceholder} className="flex-grow bg-transparent p-3 outline-none text-white placeholder:text-white/30"
                   />
                   <button onClick={() => handleAiConsult()} disabled={isAiThinking} className="bg-amber-500 text-amber-950 px-6 py-3 rounded-xl font-black hover:bg-white transition-all">
                     {isAiThinking ? '...' : (lang === 'ar' ? 'استشر' : 'Ask')}
                   </button>
                </div>
                {aiResponse && <div className="mt-4 p-4 bg-amber-500/10 rounded-xl border border-amber-500/20 text-sm italic">"{aiResponse}"</div>}
              </div>
              <div className="absolute -bottom-10 -right-10 w-40 h-40 bg-amber-500/10 rounded-full blur-3xl group-hover:scale-150 transition-all duration-1000"></div>
           </div>

           {/* Stats */}
           <div className="grid grid-cols-2 gap-4">
              <MiniStat icon="⭐" val="4.9" label={lang === 'ar' ? 'تقييمنا' : 'Rating'} onClick={() => scrollToSection('reviews-section')} />
              <MiniStat icon="🚛" val="24h" label={lang === 'ar' ? 'توصيل' : 'Delivery'} />
              <MiniStat icon="💎" val="100%" label={lang === 'ar' ? 'طبيعي' : 'Natural'} />
              <MiniStat icon="✅" val="CERT" label={lang === 'ar' ? 'مضمون' : 'Certified'} />
           </div>
        </div>

        {/* Order Form (Now simplified because products are added above) */}
        <section id="order-form" className="bg-white p-10 md:p-16 rounded-[4rem] shadow-2xl border border-amber-50 max-w-5xl mx-auto mb-24 relative scroll-mt-24">
          <div className="text-center mb-12">
            <h2 className="text-4xl font-black text-amber-950 mb-2">{t.orderNow}</h2>
            <p className="text-amber-700/60">{t.fillForm}</p>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8 mb-8">
            <InputGroup label={t.nameLabel} placeholder={t.namePlaceholder} value={customer.name} onChange={v => setCustomer({...customer, name: v})} />
            <InputGroup label={t.phoneLabel} placeholder={t.phonePlaceholder} value={customer.phone} onChange={v => setCustomer({...customer, phone: v})} />
          </div>
          <InputGroup label={t.locationLabel} placeholder={t.locationPlaceholder} value={customer.location} onChange={v => setCustomer({...customer, location: v})} />

          <div className="mt-12 bg-slate-50 p-8 rounded-[2.5rem] border border-slate-100 space-y-6">
            <h4 className="font-black text-amber-900 uppercase tracking-widest text-xs mb-4">{lang === 'ar' ? 'محتويات السلة' : 'Basket Contents'}</h4>
            {cart.length === 0 ? (
              <p className="text-center py-10 opacity-30 italic">{lang === 'ar' ? 'السلة فارغة' : 'Basket is empty'}</p>
            ) : (
              cart.map(item => <CartRow key={item.id} item={item} lang={lang} onUpdate={updateCartItem} onRemove={() => removeProductLine(item.id)} isOnly={cart.length === 1} t={t} />)
            )}
            <button onClick={() => scrollToSection('products-grid')} className="w-full py-4 rounded-2xl border-2 border-dashed border-amber-200 text-amber-800 font-bold hover:bg-amber-50 transition-all text-sm">
              {t.addProduct}
            </button>
          </div>

          <div className="mt-12 flex flex-col items-center">
             <div className="text-5xl font-black text-amber-600 mb-10 flex items-baseline gap-2">
               <span className="text-sm opacity-50 uppercase tracking-tighter">{t.total}</span>
               {totalOrderPrice} 
               <span className="text-sm font-black">{t.currency}</span>
             </div>
             <button onClick={handleSendOrder} className="w-full max-w-lg bg-amber-500 text-white font-black py-6 rounded-[2rem] text-2xl shadow-xl shadow-amber-500/20 active:scale-95 transition-all">
                {t.sendOrder}
             </button>
          </div>
        </section>

        {/* Reviews Toggleable */}
        <section id="reviews-section" className="mb-24 scroll-mt-24">
          <button onClick={() => setShowReviews(!showReviews)} className="w-full flex justify-between items-center group">
             <h2 className="text-3xl font-black text-amber-950 group-hover:opacity-70 transition-opacity">{t.reviewsTitle}</h2>
             <span className={`text-xl transition-transform duration-500 ${showReviews ? 'rotate-180' : ''}`}>▼</span>
          </button>

          <div className={`transition-all duration-700 overflow-hidden ${showReviews ? 'max-h-[3000px] opacity-100 mt-10' : 'max-h-0 opacity-0 mt-0'}`}>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
               {allReviews.map((r, i) => (
                 <div key={i} className="bg-white p-8 rounded-[2.5rem] border border-amber-50 shadow-sm relative group hover:shadow-md transition-shadow">
                    <div className="text-amber-400 text-sm mb-3">{'⭐'.repeat(r.rating)}</div>
                    <p className="text-amber-900/80 italic text-sm mb-4 leading-relaxed">"{lang === 'ar' ? r.ar.comment : r.en.comment}"</p>
                    <p className="font-black text-xs text-amber-950 flex items-center gap-2">
                      <span className="w-6 h-6 bg-amber-100 rounded-full flex items-center justify-center text-[10px]">{r.en.name.charAt(0)}</span>
                      {lang === 'ar' ? r.ar.name : r.en.name}
                    </p>
                 </div>
               ))}
            </div>
            <div className="mt-10 text-center">
               <button onClick={() => window.open(`https://wa.me/${WHATSAPP_NUMBER}?text=${encodeURIComponent(t.whatsappReviewTemplate)}`)} className="bg-white text-amber-800 border border-amber-200 px-8 py-3 rounded-2xl font-black text-sm hover:bg-amber-50">
                 {t.leaveReview} ✨
               </button>
            </div>
          </div>
        </section>

        {/* FAQ & Footer */}
        <section className="mb-24 grid grid-cols-1 lg:grid-cols-2 gap-16">
           <div>
             <h2 className="text-2xl font-black text-amber-950 mb-8">{t.faqTitle}</h2>
             <div className="space-y-4">
               {FAQS.map((f, i) => <FaqMini key={i} q={lang === 'ar' ? f.ar.q : f.en.q} a={lang === 'ar' ? f.ar.a : f.en.a} />)}
             </div>
           </div>
           <div className="bg-amber-100/30 p-10 rounded-[3rem] border border-amber-100/50 flex flex-col justify-between">
              <div>
                <h2 className="text-2xl font-black text-amber-950 mb-4">{t.whyChooseUs}</h2>
                <div className="grid grid-cols-2 gap-4">
                  <div className="text-sm font-bold opacity-60">🌿 {t.natural}</div>
                  <div className="text-sm font-bold opacity-60">🛡️ {t.labTested}</div>
                  <div className="text-sm font-bold opacity-60">🏘️ {t.direct}</div>
                  <div className="text-sm font-bold opacity-60">🚀 {t.fastDelivery}</div>
                </div>
              </div>
              <div className="mt-10 flex gap-4">
                 <a href={INSTAGRAM_URL} className="w-12 h-12 bg-amber-950 text-white rounded-2xl flex items-center justify-center font-black">IG</a>
                 <a href={`https://wa.me/${WHATSAPP_NUMBER}`} className="w-12 h-12 bg-green-600 text-white rounded-2xl flex items-center justify-center font-black">WA</a>
              </div>
           </div>
        </section>
      </div>

      {/* Styles */}
      <style>{`
        @keyframes marquee { 0% { transform: translateX(100%); } 100% { transform: translateX(-100%); } }
        .animate-marquee { animation: marquee 30s linear infinite; }
        [dir="rtl"] .animate-marquee { animation: marquee-rtl 30s linear infinite; }
        @keyframes marquee-rtl { 0% { transform: translateX(-100%); } 100% { transform: translateX(100%); } }
      `}</style>
    </div>
  );
};

