);

const FaqMini = ({ q, a }: any) => {
  const [open, setOpen] = useState(false);
  return (
    <div className="bg-white rounded-2xl border border-amber-50 overflow-hidden shadow-sm">
       <button onClick={() => setOpen(!open)} className="w-full p-6 text-start font-bold text-amber-950 text-sm flex justify-between items-center">
          <span>{q}</span>
          <span className={`transition-transform duration-300 ${open ? 'rotate-180' : ''}`}>▼</span>
       </button>
       {open && <div className="px-6 pb-6 text-xs text-amber-800/60 leading-relaxed border-t border-amber-50 pt-4 animate-in slide-in-from-top-1">{a}</div>}
    </div>
  );
};

const InputGroup = ({ label, placeholder, value, onChange }: any) => (
  <div className="space-y-3">
    <label className="text-[10px] font-black text-amber-900/30 uppercase tracking-[0.2em] ml-2">{label}</label>
    <input 
      type="text" required value={value} onChange={e => onChange(e.target.value)}
      className="w-full p-5 bg-slate-50 rounded-2xl border border-slate-100 focus:ring-4 focus:ring-amber-500/5 focus:border-amber-500 outline-none transition-all placeholder:text-slate-300 font-bold"
      placeholder={placeholder}
    />
  </div>
);

const CartRow = ({ item, lang, onUpdate, onRemove, isOnly, t }: any) => {
  const prod = PRODUCTS.find(p => p.id === item.productId);
  return (
    <div className="flex items-center gap-4 bg-white p-4 rounded-2xl shadow-sm border border-amber-100/30">
      <div className="flex-grow">
         <p className="font-black text-amber-950 text-sm">{lang === 'ar' ? prod?.titleAr : prod?.titleEn}</p>
         <select value={item.priceId} onChange={e => onUpdate(item.id, 'priceId', e.target.value)} className="bg-transparent text-[10px] font-bold text-amber-500 outline-none">
            {prod?.prices.map(pr => <option key={pr.id} value={pr.id}>{lang === 'ar' ? pr.sizeAr : pr.sizeEn} ({pr.price} {t.currency})</option>)}
         </select>
      </div>
      <div className="flex items-center bg-slate-100 rounded-xl px-2">
         <button onClick={() => onUpdate(item.id, 'quantity', Math.max(1, item.quantity - 1))} className="p-2 text-amber-900 font-black">-</button>
         <span className="w-8 text-center font-black text-xs">{item.quantity}</span>
         <button onClick={() => onUpdate(item.id, 'quantity', item.quantity + 1)} className="p-2 text-amber-900 font-black">+</button>
      </div>
      {!isOnly && (
        <button onClick={onRemove} className="text-red-400 p-2 hover:text-red-600 transition-colors">
          <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd" /></svg>
        </button>
      )}
    </div>
  );
};

export default App;
